import{_ as s,o as e,c as a,R as t}from"./chunks/framework.PZ77rLUR.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cloud/aws/diskvolume/2-efs.md","filePath":"guide/cloud/aws/diskvolume/2-efs.md","lastUpdated":1701247404000}'),l={name:"guide/cloud/aws/diskvolume/2-efs.md"},n=t(`<h2 id="_1-efs-elastic-file-system" tabindex="-1">1. EFS (Elastic File System) <a class="header-anchor" href="#_1-efs-elastic-file-system" aria-label="Permalink to &quot;1. EFS (Elastic File System)&quot;">​</a></h2><p>AWS提供的三种主要的存储：<strong>AWS Elastic Block Store (EBS)</strong>，<strong>Simple Storage Service (Amazon S3)</strong> 和 <strong>Elastic File System (EFS)</strong></p><p>AWS S3对于静态页面的托管、多媒体分发、版本管理、大数据分析、数据存档来说都非常有用。S3可以和AWS CloudFront结合使用而达到更快的上传和下载速度。</p><p>AWS EBS是可以用来做数据库或托管应用程序的持续性文件系统，EBS具有很高的IO读写速度并且即插即用。</p><p>相比前面两种存储，AWS EFS是比较新的一项服务。它提供了可以在多个EC2实例之间共享的网络文件系统，功能类似于NAS设备。可以用EFS来处理大数据分析、多媒体处理和内容管理</p><ul><li>支持Network File System vesion 4 (NFSv4) 协议</li><li>只为使用的EFS份额付费</li><li>容量可以扩展到PB级别</li><li>可以同时间支持成千上万的NFS连接</li><li>EFS的数据会保存在一个区域内的多个可用区</li><li><strong>读写一致性（Read After Write Consistency）</strong></li></ul><h2 id="_2-efs挂载" tabindex="-1">2. efs挂载 <a class="header-anchor" href="#_2-efs挂载" aria-label="Permalink to &quot;2. efs挂载&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">yum install -y nfs-utils</span></span>
<span class="line"><span style="color:#e1e4e8;"></span></span>
<span class="line"><span style="color:#e1e4e8;">mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport &lt;ip&gt;or&lt;dns&gt;:/ efs</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">yum install -y nfs-utils</span></span>
<span class="line"><span style="color:#24292e;"></span></span>
<span class="line"><span style="color:#24292e;">mount -t nfs4 -o nfsvers=4.1,rsize=1048576,wsize=1048576,hard,timeo=600,retrans=2,noresvport &lt;ip&gt;or&lt;dns&gt;:/ efs</span></span></code></pre></div><ul><li>测试磁盘吞吐量</li></ul><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-dark vp-code-dark"><code><span class="line"><span style="color:#e1e4e8;">time dd if=/dev/zero of=/mnt/efs/20G-dd-$(date +%Y%m%d%H%M%S.%3N) bs=1M count=20480 conv=fsync</span></span></code></pre><pre class="shiki github-light vp-code-light"><code><span class="line"><span style="color:#24292e;">time dd if=/dev/zero of=/mnt/efs/20G-dd-$(date +%Y%m%d%H%M%S.%3N) bs=1M count=20480 conv=fsync</span></span></code></pre></div><p>官方文档：</p><p><a href="https://docs.aws.amazon.com/zh_cn/efs/latest/ug/efs-backup-solutions.html" target="_blank" rel="noreferrer">https://docs.aws.amazon.com/zh_cn/efs/latest/ug/efs-backup-solutions.html</a></p><p><a href="https://aws.amazon.com/cn/blogs/china/quickly-build-nfs-file-system-with-efs/" target="_blank" rel="noreferrer">https://aws.amazon.com/cn/blogs/china/quickly-build-nfs-file-system-with-efs/</a></p>`,13),o=[n];function i(c,r,p,d,f,u){return e(),a("div",null,o)}const g=s(l,[["render",i]]);export{h as __pageData,g as default};
